render(() => {
const [status, setStatus] = React.useState('INITIAL');
const [title, setTitle] = React.useState('Прикрепите файл');
const [progressBar, setProgressBar] = React.useState(0);
const [isProgressKnown, setIsProgressKnown] = React.useState(false);
const [error, setError] = React.useState('');
const [showReupload, setShowReupload] = React.useState(false);
const [showDelete, setShowDelete] = React.useState(false);

const isUploading = status === 'UPLOADING' || status === 'LOADING';
const subtitle = isUploading ? 'Загружается' : 'Нет файла';

const distance = 100;
const duration = 500;
const spinnerDuration = 5000;
let startAnimation = null;

const resetState = () => {
setError('');
setTitle('Прикрепите файл');
setProgressBar(0);
setStatus('INITIAL');
setShowReupload(false);
setShowDelete(false);
};

const measure = (timestamp, status, isSpinner = false) => {
if (!startAnimation) {
startAnimation = timestamp;
}

const elapsed = timestamp - startAnimation;
const currentDuration = isSpinner ? spinnerDuration : duration;

if (isSpinner) {
if (elapsed < currentDuration) {
return requestAnimationFrame((t) => measure(t, status, isSpinner));
}
} else {
const progress = elapsed / currentDuration;
const progressValue = progress * distance;
setProgressBar(progressValue);

if (progress < 1) {
return requestAnimationFrame((t) => measure(t, status, isSpinner));
}
}

if (status === 'SUCCESS') {
setStatus(status);
setShowDelete(true);
} else if (status === 'ERROR') {
setStatus('ERROR');
setError(['Ошибка загрузки.', 'Попробуйте ещё раз']);
setShowReupload(true);
setShowDelete(true);
}
};

const startUpload = (finalStatus) => {
setTitle('Пример.docx');
setShowReupload(false);
setShowDelete(false);

if (finalStatus === 'INCORRECT_FILE') {
setStatus('ERROR');
setError('Описание первой ошибки');
setShowDelete(true);

return;
}

if (finalStatus === 'MULTI_ERROR') {
setStatus('ERROR');
setError(['Описание первой ошибки', 'Описание второй ошибки']);
setShowDelete(true);

return;
}

setError('');
setProgressBar(0);

if (!isProgressKnown) {
setStatus('LOADING');
requestAnimationFrame((t) => measure(t, finalStatus, true));
} else {
setStatus('UPLOADING');
requestAnimationFrame((t) => measure(t, finalStatus));
}
};

const handleSuccessClick = () => startUpload('SUCCESS');
const handleError = () => startUpload('ERROR');
const handeIncorrectFile = () => startUpload('INCORRECT_FILE');
const handleMultiError = () => startUpload('MULTI_ERROR');

const handleToggleChange = () => {
setIsProgressKnown((prev) => !prev);
resetState();
};

return (
<React.Fragment>
<div style={{ width: 360 }}>
<FileUploadItem
title={title}
subtitle={subtitle}
uploadStatus={status}
progressBar={isProgressKnown ? progressBar : undefined}
progressBarAvailable={isProgressKnown}
uploadDate='22.07.2024'
size={2 * 1024 * 1024} // 2mb
error={error}
reupload={showReupload ? { onClick: handleError } : undefined}
showDelete={showDelete}
onDelete={() => resetState()}
>
<FileUploadItem.StatusControl />
<FileUploadItem.Content />
<FileUploadItem.Actions />
</FileUploadItem>
</div>
<Gap size={20} />
<div>
<Button size={32} onClick={handleSuccessClick}>
Успех
</Button>
<Gap size={8} direction='horizontal' />
<Button size={32} onClick={handleError}>
Ошибка загрузки
</Button>
<Gap size={8} direction={isMobile() ? 'vertical' : 'horizontal'} />
<Button size={32} onClick={handeIncorrectFile}>
Некорректный файл
</Button>
<Gap size={8} direction={isMobile() ? 'vertical' : 'horizontal'} />
<Button size={32} onClick={handleMultiError}>
Несколько ошибок
</Button>
</div>
<Gap size={20} />
<Switch
checked={isProgressKnown}
label='Известен прогресс загрузки'
onChange={handleToggleChange}
/>
</React.Fragment>
);
});

